static void animation_phase(void) {
    if (get_current_wpm() <= CAT_IDLE_SPEED) {
        cat_current_idle_frame = (cat_current_idle_frame + 1) % CAT_IDLE_FRAMES;
        oled_write_raw_P(idle[abs((CAT_IDLE_FRAMES - 1) - cat_current_idle_frame)], CAT_ANIM_SIZE);
    }
    if (get_current_wpm() > CAT_IDLE_SPEED && get_current_wpm() < CAT_TAP_SPEED) {
        oled_write_raw_P(prep[0], CAT_ANIM_SIZE);
    }
    if (get_current_wpm() >= CAT_TAP_SPEED) {
        cat_current_tap_frame = (cat_current_tap_frame + 1) % CAT_TAP_FRAMES;
        oled_write_raw_P(tap[abs((CAT_TAP_FRAMES - 1) - cat_current_tap_frame)], CAT_ANIM_SIZE);
    }
}

void render_cat(void) {
    if (timer_elapsed32(cat_anim_timer) > CAT_ANIM_FRAME_DURATION) {
        cat_anim_timer = timer_read32();
        animation_phase();
    }
}
